#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;

int n,q,m,a[N];
long long t[N<<2],add[N<<2],mul[N<<2];

void build(int cur,int l,int r){
    add[cur]=0,mul[cur]=1;
    if(l==r){
        t[cur]=a[l]%m;
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=(t[cur*2]+t[cur*2+1])%m;
}

void push_down(int cur,int l,int r){
    int mid=l+r>>1;
    t[cur*2]=t[cur*2]*mul[cur]%m,mul[cur*2]=mul[cur*2]*mul[cur]%m,add[cur*2]=add[cur*2]*mul[cur]%m;
    t[cur*2+1]=t[cur*2+1]*mul[cur]%m,mul[cur*2+1]=mul[cur*2+1]*mul[cur]%m,add[cur*2+1]=add[cur*2+1]*mul[cur]%m;
    t[cur*2]=(t[cur*2]+add[cur]*(mid-l+1))%m,add[cur*2]=(add[cur*2]+add[cur])%m;
    t[cur*2+1]=(t[cur*2+1]+add[cur]*(r-mid))%m,add[cur*2+1]=(add[cur*2+1]+add[cur])%m;
    add[cur]=0,mul[cur]=1;
}

void modify(int cur,int l,int r,int x,int y,int k,int op){
    if(x<=l && r<=y){
        if(op==0)
            t[cur]=t[cur]*k%m,add[cur]=add[cur]*k%m,mul[cur]=mul[cur]*k%m;
        else
            t[cur]=(t[cur]+k*(r-l+1))%m,add[cur]=(add[cur]+k)%m;
        return;
    }
    push_down(cur,l,r);
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x,y,k,op);
    if(y>mid)
        modify(cur*2+1,mid+1,r,x,y,k,op);
    t[cur]=(t[cur*2]+t[cur*2+1])%m;
}

int query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    push_down(cur,l,r);
    int mid=l+r>>1,ans=0;
    if(x<=mid)
        ans+=query(cur*2,l,mid,x,y);
    if(y>mid)
        ans+=query(cur*2+1,mid+1,r,x,y);
    return ans%m;
}

int main(){
    scanf("%d%d%d",&n,&q,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    build(1,1,n);
    while(q--){
        int op,x,y,k;
        scanf("%d%d%d",&op,&x,&y);
        if(op<3){
            scanf("%d",&k);
            modify(1,1,n,x,y,k,op-1);
        }else
            printf("%d\n",query(1,1,n,x,y));
    }
    return 0;
}
